import * as React from 'react'
import styled, { css, useTheme } from 'styled-components'

import { breakpoints } from '../../styles/breakpoints'
import { Icon, IconName } from '../Icon'

const Spacer = styled.span`
  padding-left: 1rem;
`

type StyledButtonProperties = {
  $clear: boolean
  $large: boolean
  $withIcon: boolean
  $round: boolean
}

const StyledButton = styled.button<StyledButtonProperties>(
  ({ $clear, $large, $round, $withIcon, theme: { color, boxShadow, borderRadius } }) => css`
    outline: none;
    border: 0;
    font-family: 'Hind';
    border-radius: ${$round ? borderRadius.xl : borderRadius.xs};
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: ${$withIcon ? '0.7rem' : $large ? '1.125rem 1rem' : '0.875rem 1rem'};
    color: ${$clear ? color.primaryText : color.buttonText};

    transition: box-shadow 150ms ease-in;
    z-index: 1;
    background-color: ${$clear ? color.buttonClear : color.buttonPrimary};

    &:hover {
      cursor: pointer;
      background-color: ${$clear ? color.buttonClearHover : color.buttonPrimaryHover};
    }

    &:focus {
      box-shadow: ${boxShadow.outerBorder};
    }

    &:disabled {
      background-color: ${$clear ? color.buttonClear : color.buttonPrimary};
      opacity: 0.4;
    }

    @media ${breakpoints.M} {
      padding: ${$withIcon ? '1rem' : $large ? '1.125rem 1.5rem' : '0.875rem 1.5rem'};
    }
  `
)

type DefaultProperties = {
  /**
   * Clear button styles leaving just a text
   */
  clear?: boolean
  round?: boolean
  /**
   * Is the button large?
   */
  large?: boolean
  /**
   * Does the button have an icon?
   */
  icon?: IconName
  /**
   * Size of the icon
   */
  iconSize?: number
  /**
   * Is the button disabled?
   */
  disabled?: boolean
  /**
   * Does the button have an icon?
   */
  children?: string | React.ReactNode
  /**
   * Optional click handler
   */
  onClick?: () => void
}

// Remove StyledButton props from ButtonProps to avoid duplicate props
type ButtonProperties = DefaultProperties &
  Omit<React.ComponentProps<'button'>, keyof DefaultProperties>

/**
 * Primary UI component for user interaction
 */
export const Button: React.FC<React.PropsWithChildren<ButtonProperties>> = ({
  children,
  large = false,
  clear = false,
  round = false,
  icon,
  iconSize,
  ...properties
}: ButtonProperties) => {
  const { color } = useTheme()

  return (
    <StyledButton
      type="button"
      $large={large}
      $clear={clear}
      $round={round}
      $withIcon={!!icon}
      {...properties}
    >
      {icon && (
        <Icon color={clear ? color.primaryText : color.buttonText} size={iconSize} name={icon} />
      )}
      {icon && children && <Spacer />}
      {children}
    </StyledButton>
  )
}

import styled, { useTheme } from 'styled-components'

const StyledSVG = styled.svg`
  display: block;
`

export type IconName =
  | 'arrow-right'
  | 'arrow-left'
  | 'cross'
  | 'cart'
  | 'minus'
  | 'plus'
  | 'moon'
  | 'sun'
  | 'star'

type IconProps = {
  name: IconName
  color?: string
  size?: number | string
}

export const Icon = ({ name, color, size = '1.5rem' }: IconProps) => {
  const { color: themeColor } = useTheme()
  return (
    <StyledSVG
      stroke={color || themeColor.primaryText}
      width={size}
      height={size}
      style={{ minWidth: size }}
    >
      <use xlinkHref={`/sprite-map.svg#${name}`} />
    </StyledSVG>
  )
}

import * as React from 'react'
import { CSSTransition } from 'react-transition-group'

import { Portal } from '../Portal'
import { useKey } from '../../hooks/useKeyboard'
import { Button } from '../Button'
import { useLockBodyScroll } from '../../hooks/useBodyScrollLock'

import { ModalContent, TopBar, Backdrop } from './Modal.styles'

type ModalProps = {
  isOpen: boolean
  onClose: () => void
}

export const Modal: React.FC<React.PropsWithChildren<ModalProps>> = ({
  children,
  isOpen,
  onClose,
}) => {
  useKey('escape', onClose)
  useLockBodyScroll(isOpen)
  const contentRef = React.useRef(null)
  const backdropRef = React.useRef(null)

  return (
    <Portal selector="#modal">
      <CSSTransition
        in={isOpen}
        timeout={300}
        classNames="modal"
        unmountOnExit
        nodeRef={contentRef}
      >
        <ModalContent data-testid="modal" ref={contentRef}>
          <TopBar>
            <Button
              data-testid="modal-close-btn"
              onClick={onClose}
              clear
              round
              icon="cross"
              aria-label="close modal"
              iconSize={16}
            />
          </TopBar>
          {children}
        </ModalContent>
      </CSSTransition>

      <CSSTransition
        in={isOpen}
        timeout={300}
        classNames="backdrop"
        unmountOnExit
        nodeRef={backdropRef}
      >
        <Backdrop data-testid="modal-backdrop" ref={backdropRef} onClick={onClose} />
      </CSSTransition>
    </Portal>
  )
}

import { combineReducers, configureStore } from '@reduxjs/toolkit'

import { reducer as cart } from './cart'
import { reducer as order } from './order'

export const rootReducer = combineReducers({
  cart,
  order,
})

export const store = configureStore({
  reducer: rootReducer,
})

export type AppDispatch = typeof store.dispatch
export type RootState = ReturnType<typeof store.getState>

